# Problem: Implement a pytest-like marker system with skip/xfail support and filtered test runner.
#
# Approach:
#   - Use __getattr__ on MarkFactory to dynamically create Marker objects.
#   - Marker.__call__ distinguishes between direct decoration (@mark.slow) and
#     parameterized decoration (@mark.skip(reason="...")) by checking if the
#     first positional arg is callable.
#   - FilterRunner collects test_ functions, sorts alphabetically, applies
#     exclude then include filtering, and handles skip/xfail semantics.
#
# Time complexity: O(n log n) for sorting tests, O(n*m) for marker filtering.
# Space complexity: O(n) for storing test functions and results.
#
# Key steps:
#   1. MarkerInfo stores marker name and kwargs.
#   2. Marker attaches MarkerInfo to function._markers on decoration.
#   3. MarkFactory returns Marker instances via __getattr__.
#   4. FilterRunner collects, filters, and runs tests with skip/xfail handling.

class MarkerInfo:
    def __init__(self, name: str, **kwargs):
        self.name = name
        self.kwargs = kwargs


class Marker:
    def __init__(self, name: str, **kwargs):
        self.name = name
        self.kwargs = kwargs

    def __call__(self, *args, **kwargs):
        # Direct decoration: @mark.slow applied to a function
        if args and callable(args[0]) and not kwargs:
            func = args[0]
            if not hasattr(func, '_markers'):
                func._markers = []
            func._markers.append(MarkerInfo(self.name, **self.kwargs))
            return func
        # Parameterized: @mark.skip(reason="...") returns a new Marker that acts as decorator
        return Marker(self.name, **kwargs)


class MarkFactory:
    def __getattr__(self, name):
        return Marker(name)


mark = MarkFactory()


class TestResult:
    def __init__(self, name: str, passed: bool, error: str | None = None):
        self.name = name
        self.passed = passed
        self.error = error


class FilterRunner:
    def __init__(self, namespace: dict):
        # Collect test functions (names starting with test_) from namespace
        self.tests = {
            name: func for name, func in namespace.items()
            if name.startswith('test_') and callable(func)
        }

    def run(self, include_markers=None, exclude_markers=None):
        results = []
        # Run tests in alphabetical order
        for name in sorted(self.tests):
            func = self.tests[name]
            markers = getattr(func, '_markers', [])
            marker_names = {m.name for m in markers}

            # Exclude filtering applied first
            if exclude_markers and marker_names & set(exclude_markers):
                continue

            # Include filtering: test must have at least one matching marker
            if include_markers and not (marker_names & set(include_markers)):
                continue

            # Built-in skip handling
            if 'skip' in marker_names:
                skip_marker = next(m for m in markers if m.name == 'skip')
                reason = skip_marker.kwargs.get('reason', '')
                results.append(TestResult(name, passed=False, error=f"SKIPPED: {reason}"))
                continue

            # Check for xfail marker
            is_xfail = 'xfail' in marker_names

            try:
                func()
                if is_xfail:
                    # Test passed but was expected to fail
                    results.append(TestResult(name, passed=False,
                                              error="XPASS: test was expected to fail but passed"))
                else:
                    results.append(TestResult(name, passed=True, error=None))
            except Exception:
                if is_xfail:
                    # Expected failure
                    results.append(TestResult(name, passed=True, error="XFAIL"))
                else:
                    results.append(TestResult(name, passed=False, error=None))

        return results
